class Solution:
    def solve(self, products) -> List[Dict[str, int]]:
        category_counts = {};
        for product in products:
            category = product['category'];
            if category in category_counts:
                category_counts[category] += 1;
            else:
                category_counts[category] = 1;
        return sorted(category_counts.items(), key=lambda x: x[0]);
